// ── APP ────────────────────────────────────────────────────────────────────────
export default function QuantX() {
  const [tab, setTab] = useState("signals");
  const [openSet, setOpenSet] = useState(new Set([0]));
  const [now, setNow] = useState(new Date());
  const [logEntries, setLogEntries] = useState([]);
  const [logLoaded, setLogLoaded] = useState(false);

  // Clock
  useEffect(() => {
    const t = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  // Load persisted log on mount
  useEffect(() => {
    loadLog().then(entries => {
      setLogEntries(entries);
      setLogLoaded(true);
    });
  }, []);

  const toggle = i => setOpenSet(prev => {
    const next = new Set(prev);
    next.has(i) ? next.delete(i) : next.add(i);
    return next;
  });

  const addLogEntry = (entry) => {
    const updated = [...logEntries, entry];
    setLogEntries(updated);
    saveLog(updated);
    setTab("log");
  };

  const updateLogEntry = (id, changes) => {
    const updated = logEntries.map(e => e.id === id ? { ...e, ...changes } : e);
    setLogEntries(updated);
    saveLog(updated);
  };

  const deleteLogEntry = (id) => {
    const updated = logEntries.filter(e => e.id !== id);
    setLogEntries(updated);
    saveLog(updated);
  };

  const day = now.getDay(), h = now.getHours(), m = now.getMinutes();
  const isOpen = day>=1 && day<=5 && h*60+m>=570 && h*60+m<960;
  const pad = n => String(n).padStart(2, "0");
  const DAYS = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  const pendingCount = logEntries.filter(e => e.outcome === "pending").length;

  const TABS = [
    { key:"signals", label:"Signals" },
    { key:"log",     label:"Log", badge: pendingCount > 0 ? pendingCount : null },
    { key:"research",label:"Research" },
  ];

  return (
    <div style={{
      minHeight:"100vh", background:C.bg, color:C.white,
      fontFamily:C.font, maxWidth:430, margin:"0 auto",
      position:"relative", overflowX:"hidden",
    }}>
      <style>{`
        * { box-sizing:border-box; margin:0; padding:0; }
        input::-webkit-outer-spin-button, input::-webkit-inner-spin-button { -webkit-appearance:none; }
        input[type=number] { -moz-appearance:textfield; }
        textarea { -webkit-appearance:none; }
        @keyframes fadeUp { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
        @keyframes slideDown { from{opacity:0;transform:translateY(-4px)} to{opacity:1;transform:translateY(0)} }
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.2} }
        button { transition:opacity 0.1s, transform 0.1s; }
        button:active { opacity:0.65; transform:scale(0.98); }
      `}</style>

      {/* Header */}
      <div style={{
        position:"sticky", top:0, zIndex:100,
        background:"rgba(0,0,0,0.94)", backdropFilter:"blur(24px)", WebkitBackdropFilter:"blur(24px)",
        borderBottom:`1px solid ${C.border}`,
        padding:"14px 20px",
        display:"flex", justifyContent:"space-between", alignItems:"center",
      }}>
        <div style={{ display:"flex", alignItems:"center", gap:10 }}>
          <SignalMark size={32}/>
          <div>
            <div style={{ fontSize:16, fontWeight:700, letterSpacing:"-0.03em", color:C.white, lineHeight:1.1 }}>QuantX</div>
            <div style={{ fontSize:8, color:C.dimmer, letterSpacing:"0.14em", fontWeight:500, marginTop:1 }}>PAIRS TRADING</div>
          </div>
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <div style={{ display:"flex", alignItems:"center", gap:5 }}>
            <div style={{
              width:6, height:6, borderRadius:"50%",
              background:isOpen?C.green:"rgba(255,255,255,0.18)",
              boxShadow:isOpen?`0 0 6px ${C.green}`:"none",
              animation:isOpen?"pulse 2s infinite":"none",
            }}/>
            <span style={{ fontSize:10, fontWeight:600, color:isOpen?C.green:C.dimmer, letterSpacing:"0.08em" }}>
              {isOpen?"OPEN":"CLOSED"}
            </span>
          </div>
          <span style={{ fontSize:10, color:"rgba(255,255,255,0.18)", fontFamily:C.mono }}>
            {DAYS[day]} {pad(h)}:{pad(m)}
          </span>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display:"flex", borderBottom:`1px solid ${C.border}`, padding:"0 20px" }}>
        {TABS.map(({ key, label, badge }) => (
          <button key={key} onClick={() => setTab(key)} style={{
            background:"transparent", border:"none", cursor:"pointer",
            padding:"14px 0", marginRight:24,
            fontSize:14, fontWeight:tab===key?600:400,
            color:tab===key?C.white:C.dimmer,
            borderBottom:`2px solid ${tab===key?C.accent:"transparent"}`,
            letterSpacing:"-0.01em",
            transition:"color 0.15s, border-color 0.15s",
            position:"relative",
            display:"flex", alignItems:"center", gap:6,
          }}>
            {label}
            {badge && (
              <span style={{
                fontSize:9, fontWeight:700,
                background:C.yellow, color:"#000",
                borderRadius:20, padding:"1px 5px",
                letterSpacing:"0.02em",
              }}>{badge}</span>
            )}
          </button>
        ))}
      </div>

      {/* Content */}
      {tab === "signals" && (
        <div style={{ padding:"20px 20px", display:"flex", flexDirection:"column", gap:10 }}>
          <div style={{ marginBottom:6 }}>
            <h1 style={{ fontSize:22, fontWeight:600, letterSpacing:"-0.03em", marginBottom:3, color:C.white }}>Today's Signals</h1>
            <p style={{ fontSize:12, color:C.dimmer }}>
              {isOpen ? "Market open — enter prices to generate signals" : "Market closed — opens 9:30 AM ET weekdays"}
            </p>
          </div>
          {PAIRS.map((pair, i) => (
            <div key={pair.lead} style={{ animation:`fadeUp 0.25s ease ${i*0.06}s both` }}>
              <PairAccordion
                pair={pair}
                open={openSet.has(i)}
                onToggle={() => toggle(i)}
                onLogTrade={addLogEntry}
              />
            </div>
          ))}
        </div>
      )}

      {tab === "log" && (
        <TradeLogPage
          entries={logEntries}
          onUpdate={updateLogEntry}
          onDelete={deleteLogEntry}
        />
      )}

      {tab === "research" && <ResearchPage/>}

      {/* Bottom fade */}
      <div style={{
        position:"fixed", bottom:0, left:"50%", transform:"translateX(-50%)",
        width:"100%", maxWidth:430, height:60,
        background:`linear-gradient(to top, ${C.bg} 40%, transparent)`,
        zIndex:50, pointerEvents:"none",
      }}/>
    </div>
  );
}
